    // ---- SAFE LOADER FOR JSDELIVR ----
    function loadRepoScript(){
      return new Promise((resolve, reject)=>{
        const s=document.createElement('script');

        // 🔗 CHANGE THIS if your file path differs
        s.src='https://cdn.jsdelivr.net/gh/jared20010813-stack/NexusForge@main/app.js';

        s.onload=resolve;
        s.onerror=reject;
        document.body.appendChild(s);
      });
    }

    // ---- FALLBACK CORE (if repo fails) ----
    let tabs=[],current=0;

    function norm(u){
      try{return new URL(u).href}
      catch{
        try{return new URL('https://'+u).href}
        catch{return null}
      }
    }

    function render(){
      const t=document.getElementById('tabs');
      t.innerHTML='';
      tabs.forEach((tab,i)=>{
        const d=document.createElement('div');
        d.className='tab';
        d.textContent=tab.title;
        d.onclick=()=>switchTab(i);
        t.appendChild(d);
      });
    }

    function load(){
      if(!tabs.length)return;
      document.getElementById('frame').src=tabs[current].url;
      render();
    }

    function add(u){
      const v=norm(u);
      if(!v) return alert('bad url');
      tabs.push({url:v,title:new URL(v).hostname});
      current=tabs.length-1;
      load();
    }

    function switchTab(i){
      current=i;
      load();
    }

    function NF_go(){
      const val=document.getElementById('url').value;
      if(window.NexusForge && NexusForge.go){
        NexusForge.go(val); // use repo logic
      }else{
        add(val); // fallback
      }
    }

    // ---- INIT ----
    loadRepoScript()
      .then(()=>{
        if(window.NexusForge && NexusForge.init){
          NexusForge.init({
            frameId:'frame',
            tabsId:'tabs'
          });
        }
      })
      .catch(()=>{
        console.warn('Repo failed, using fallback');
        add('https://example.com');
      });




